import{_ as e,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"快速上手 AI App Factory：从安装到运行第一个应用 | agent-app-factory","description":"学习如何快速启动 AI App Factory，从安装配置 CLI 工具到理解 7 阶段流水线的工作原理，掌握初始化项目并开始你的第一个应用生成之旅。本章节包含快速开始、安装配置、项目初始化和流水线概览四个核心课程，帮助你全面了解从想法到可运行应用的端到端自动化流程。","frontmatter":{"title":"快速上手 AI App Factory：从安装到运行第一个应用 | agent-app-factory","sidebarTitle":"上手","subtitle":"上手","description":"学习如何快速启动 AI App Factory，从安装配置 CLI 工具到理解 7 阶段流水线的工作原理，掌握初始化项目并开始你的第一个应用生成之旅。本章节包含快速开始、安装配置、项目初始化和流水线概览四个核心课程，帮助你全面了解从想法到可运行应用的端到端自动化流程。","order":10},"headers":[],"relativePath":"zh/hyz1992/agent-app-factory/start/index.md","filePath":"zh/hyz1992/agent-app-factory/start/index.md"}'),l={name:"zh/hyz1992/agent-app-factory/start/index.md"};function o(n,a,p,s,d,c){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="上手" tabindex="-1">上手 <a class="header-anchor" href="#上手" aria-label="Permalink to &quot;上手&quot;">​</a></h1><p>本章节帮助你快速上手 AI App Factory，了解核心价值、安装配置工具，并理解 7 阶段流水线的工作原理，为生成第一个应用做好准备。</p><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><p>建议按照以下顺序学习本章节内容：</p><h3 id="_1-快速开始-从想法到应用" tabindex="-1">1. <a href="./../getting-started/">快速开始：从想法到应用</a> <a class="header-anchor" href="#_1-快速开始-从想法到应用" aria-label="Permalink to &quot;1. [快速开始：从想法到应用](../getting-started/)&quot;">​</a></h3><p>了解 AI App Factory 的核心价值和前置要求，通过一个完整的案例体验从想法到应用的端到端流程。</p><ul><li>理解基于检查点的多 Agent 协作机制</li><li>了解 7 阶段流水线的完整工作流程</li><li>掌握提供清晰产品描述的技巧</li></ul><h3 id="_2-安装与配置" tabindex="-1">2. <a href="./../installation/">安装与配置</a> <a class="header-anchor" href="#_2-安装与配置" aria-label="Permalink to &quot;2. [安装与配置](../installation/)&quot;">​</a></h3><p>全局安装 CLI 工具，配置 AI 助手（Claude Code/OpenCode）及相关环境。</p><ul><li>使用 npm 全局安装 agent-app-factory</li><li>配置 Claude Code 或 OpenCode</li><li>验证安装是否成功</li></ul><h3 id="_3-初始化-factory-项目" tabindex="-1">3. <a href="./../init-project/">初始化 Factory 项目</a> <a class="header-anchor" href="#_3-初始化-factory-项目" aria-label="Permalink to &quot;3. [初始化 Factory 项目](../init-project/)&quot;">​</a></h3><p>使用 <code>factory init</code> 命令初始化目录，了解生成的项目结构和配置文件。</p><ul><li>执行项目初始化命令</li><li>理解项目目录结构和配置文件</li><li>准备产品想法输入</li></ul><h3 id="_4-7-阶段流水线概览" tabindex="-1">4. <a href="./../pipeline-overview/">7 阶段流水线概览</a> <a class="header-anchor" href="#_4-7-阶段流水线概览" aria-label="Permalink to &quot;4. [7 阶段流水线概览](../pipeline-overview/)&quot;">​</a></h3><p>深入理解从 Bootstrap 到 Preview 的完整流水线流程，各阶段的输入输出和检查点机制。</p><ul><li>理解 7 个阶段的目标和产物</li><li>掌握检查点机制和人工确认流程</li><li>学习如何控制流水线执行</li></ul><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>开始本章节学习前，你需要：</p><div class="warning custom-block"><p class="custom-block-title">前置要求</p><ol><li><strong>Node.js 环境</strong>：已安装 Node.js v18 或更高版本</li><li><strong>AI 编程助手</strong>：必须配置以下工具之一 <ul><li><a href="https://claude.ai/code" target="_blank" rel="noreferrer">Claude Code</a>（推荐）⭐</li><li><a href="https://opencode.design/" target="_blank" rel="noreferrer">OpenCode</a> 或其他支持 Agent 模式的 AI 助手</li></ul></li><li><strong>基础命令行操作</strong>：能够使用终端执行命令</li></ol></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章节学习后，你将掌握：</p><ul><li>✅ AI App Factory 的核心工作原理</li><li>✅ CLI 工具的安装和配置</li><li>✅ 项目初始化和结构理解</li><li>✅ 7 阶段流水线的完整流程</li></ul><p>接下来，建议学习 <strong><a href="./../../platforms/">平台与集成</a></strong> 章节，了解如何在不同的 AI 助手上运行流水线。</p>',23)])])}const f=e(l,[["render",o]]);export{u as __pageData,f as default};
